package cl.duoc.vetcontrol.historial.model;
import jakarta.persistence.*; import java.time.*;
@Entity @Table(name="historial_clinico")
public class HistorialClinico { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private Long mascotaId; @Column(nullable=false) private LocalDateTime fecha; @Column(nullable=false,length=60) private String tipo; @Column(nullable=false,length=500) private String detalle; private Long referenciaExternaId; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getMascotaId(){return mascotaId;} public void setMascotaId(Long mascotaId){this.mascotaId=mascotaId;} public LocalDateTime getFecha(){return fecha;} public void setFecha(LocalDateTime fecha){this.fecha=fecha;} public String getTipo(){return tipo;} public void setTipo(String tipo){this.tipo=tipo;} public String getDetalle(){return detalle;} public void setDetalle(String detalle){this.detalle=detalle;} public Long getReferenciaExternaId(){return referenciaExternaId;} public void setReferenciaExternaId(Long referenciaExternaId){this.referenciaExternaId=referenciaExternaId;} }
